/* ── Toggle switch ── */

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-label {
    font-size: 0.95rem;
