@page "/settings"
@rendermode InteractiveServer
@using sv_719b9314b6014e88921a3b55014142e6.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li class="@(section == _activeSection ? "active" : "")" @onclick="() => SetSection(section)">
                    <span class="nav-icon">@GetSectionIcon(section)</span>
                    @section
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">Loading…</div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfile()
                    break;
                case "Notifications":
                    @RenderNotifications()
                    break;
                case "Security":
                    @RenderSecurity()
                    break;
                case "Appearance":
                    @RenderAppearance()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "")">@_toastText</div>
        }
    </div>
</div>

@* ──────────── Profile Section ──────────── *@

@code {
    private RenderFragment RenderProfile() => __builder =>
    {
        <section class="settings-section">
            <h2>Profile</h2>
            <div class="avatar-area">
                <img src="@_profileDisplayName" alt="avatar" class="avatar-preview"
                     onerror="this.style.display='none'" />
                @* Show the avatar from the URL field *@
                @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                {
                    <img src="@_profileAvatarUrl" alt="avatar" class="avatar-preview" />
                }
                else
                {
                    <div class="avatar-placeholder">No avatar</div>
                }
                <span class="avatar-url-label">@_profileAvatarUrl</span>
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" @bind="_profileDisplayName" class="form-input" />
            </div>
            <div class="form-group">
                <label>Email</label>
                <input type="email" @bind="_profileEmail" class="form-input" />
            </div>
            <div class="form-group">
                <label>Avatar URL</label>
                <input type="url" @bind="_profileAvatarUrl" class="form-input" />
            </div>
            <div class="form-group">
                <label>Bio</label>
                <textarea @bind="_profileBio" class="form-input form-textarea" rows="4"></textarea>
            </div>
            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };
}

@* ──────────── Notifications Section ──────────── *@

@code {
    private RenderFragment RenderNotifications() => __builder =>
    {
        <section class="settings-section">
            <h2>Notifications</h2>

            <div class="toggle-row">
                <label class="toggle-label">Email Notifications</label>
                <label class="switch">
                    <input type="checkbox" @bind="_notifEmail" />
                    <span class="slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <label class="toggle-label">Push Notifications</label>
                <label class="switch">
                    <input type="checkbox" @bind="_notifPush" />
                    <span class="slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <label class="toggle-label">Weekly Digest</label>
                <label class="switch">
                    <input type="checkbox" @bind="_notifWeeklyDigest" />
                    <span class="slider"></span>
                </label>
            </div>

            <h3 class="sub-heading">Muted Channels</h3>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <label class="channel-item">
                        <input type="checkbox" checked="@_mutedChannels.Contains(ch)"
                               @onchange="e => ToggleMutedChannel(ch, (bool)(e.Value ?? false))" />
                        <span>@ch</span>
                    </label>
                }
            </div>
            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </section>
    };
}

@* ──────────── Security Section ──────────── *@

@code {
    private RenderFragment RenderSecurity() => __builder =>
    {
        <section class="settings-section">
            <h2>Security</h2>

            @* Change Password Panel *@
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>Change Password</span>
                    <span class="chevron @(_passwordPanelOpen ? "open" : "")">▸</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label>Current Password</label>
                            <input type="password" @bind="_currentPassword" class="form-input" />
                        </div>
                        <div class="form-group">
                            <label>New Password</label>
                            <input type="password" @bind="_newPassword" class="form-input" />
                        </div>
                        <div class="form-group">
                            <label>Confirm Password</label>
                            <input type="password" @bind="_confirmPassword" class="form-input" />
                        </div>
                        @if (_lastPasswordChange.HasValue)
                        {
                            <p class="hint-text">Last changed: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
                        }
                        <div class="button-row">
                            <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                        </div>
                    </div>
                }
            </div>

            @* Two-Factor Auth *@
            <div class="toggle-row" style="margin-top:1.5rem;">
                <label class="toggle-label">
                    Two-Factor Authentication
                    <span class="status-badge @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </label>
                <label class="switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="slider"></span>
                </label>
            </div>

            @* Active Sessions *@
            <h3 class="sub-heading" style="margin-top:2rem;">Active Sessions</h3>
            <div class="table-wrapper">
                <table class="data-table">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            var s = session;
                            <tr>
                                <td>@s.Device</td>
                                <td>@s.Location</td>
                                <td>@FormatLastActive(s.LastActive)</td>
                                <td>
                                    @if (s.Id != _currentSessionId)
                                    {
                                        <button class="btn btn-danger btn-sm"
                                                @onclick="() => PromptRevokeSession(s.Id, s.Device)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="current-label">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>

            @* Revoke confirmation dialog *@
            @if (_revokeConfirmVisible)
            {
                <div class="modal-overlay" @onclick="CancelRevoke">
                    <div class="modal-dialog" @onclick:stopPropagation="true">
                        <h4>Revoke Session</h4>
                        <p>Are you sure you want to revoke the session on <strong>@_revokeDeviceName</strong>?</p>
                        <div class="button-row">
                            <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        </div>
                    </div>
                </div>
            }
        </section>
    };
}

@* ──────────── Appearance Section ──────────── *@

@code {
    private RenderFragment RenderAppearance() => __builder =>
    {
        <section class="settings-section">
            <h2>Appearance</h2>

            <div class="form-group">
                <label class="group-label">Theme</label>
                <div class="radio-group">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        var t = theme;
                        <label class="radio-item">
                            <input type="radio" name="theme" value="@t"
                                   checked="@(_appTheme == t)"
                                   @onchange="() => _appTheme = t" />
                            @t
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label class="group-label">Font Size</label>
                <div class="radio-group">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        var sz = size;
                        <label class="radio-item">
                            <input type="radio" name="fontSize" value="@sz"
                                   checked="@(_appFontSize == sz)"
                                   @onchange="() => _appFontSize = sz" />
                            @sz
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label>Language</label>
                <select @bind="_appLanguage" class="form-input">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="toggle-row">
                <label class="toggle-label">Compact Mode</label>
                <label class="switch">
                    <input type="checkbox" @bind="_appCompactMode" />
                    <span class="slider"></span>
                </label>
            </div>

            @* Live preview *@
            <h3 class="sub-heading" style="margin-top:1.5rem;">Preview</h3>
            <div class="preview-box @GetPreviewClasses()">
                <h4 style="margin:0 0 .5rem;">Sample Heading</h4>
                <p style="margin:0;">This is how your content will look with the selected appearance settings.</p>
                <button class="preview-btn" style="margin-top:.75rem;">Sample Button</button>
            </div>

            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };
}

@* ──────────── Code-behind ──────────── *@

@code {
    // Section navigation
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _toastVisible;
    private string _toastText = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile state
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // Notifications state
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeeklyDigest;
    private List<string> _mutedChannels = [];
    private readonly List<string> _allChannels = ["announcements", "marketing", "social", "engineering", "support"];

    // Security state
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private readonly string _currentSessionId = "sess-1"; // Treat first session as current
    private bool _revokeConfirmVisible;
    private string _revokeSessionId = "";
    private string _revokeDeviceName = "";

    // Appearance state
    private string _appTheme = "Light";
    private string _appFontSize = "Medium";
    private string _appLanguage = "English";
    private bool _appCompactMode;
    private readonly List<string> _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        var profile = profileTask.Result;
        _savedProfile = profile;
        ApplyProfile(profile);

        var notif = notifTask.Result;
        _notifEmail = notif.EmailNotifications;
        _notifPush = notif.PushNotifications;
        _notifWeeklyDigest = notif.WeeklyDigest;
        _mutedChannels = new List<string>(notif.MutedChannels);

        var security = securityTask.Result;
        _twoFactorEnabled = security.TwoFactorEnabled;
        _lastPasswordChange = security.LastPasswordChange;
        _sessions = new List<ActiveSession>(security.Sessions);

        var appearance = appearanceTask.Result;
        _appTheme = appearance.Theme;
        _appFontSize = appearance.FontSize;
        _appLanguage = appearance.Language;
        _appCompactMode = appearance.CompactMode;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;
    }

    private void SetSection(string section) => _activeSection = section;

    // ── Profile ──

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notifications ──

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!muted)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifWeeklyDigest, new List<string>(_mutedChannels));
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        ShowToast("Notification preferences saved.");
    }

    // ── Security ──

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Password cannot be empty.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("Passwords do not match.", isError: true);
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _lastPasswordChange = DateTime.UtcNow;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(string sessionId, string deviceName)
    {
        _revokeSessionId = sessionId;
        _revokeDeviceName = deviceName;
        _revokeConfirmVisible = true;
    }

    private async Task ConfirmRevoke()
    {
        await SettingsService.RevokeSessionAsync(_revokeSessionId);
        _sessions.RemoveAll(s => s.Id == _revokeSessionId);
        _revokeConfirmVisible = false;
        ShowToast("Session revoked.");
    }

    private void CancelRevoke() => _revokeConfirmVisible = false;

    // ── Appearance ──

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_appTheme, _appFontSize, _appLanguage, _appCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        ShowToast("Appearance settings saved.");
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string> { "preview-area" };
        classes.Add(_appTheme switch { "Dark" => "preview-dark", "System" => "preview-system", _ => "preview-light" });
        classes.Add(_appFontSize switch { "Small" => "preview-font-sm", "Large" => "preview-font-lg", _ => "preview-font-md" });
        if (_appCompactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    // ── Helpers ──

    private string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastText = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }
}

