    letter-spacing: 0.03em;
}

.data-table td {
    padding: 0.65rem 0.75rem;
    border-bottom: 1px solid #f0f0f0;
    color: #212529;
}

.current-label {
    font-size: 0.8rem;
    color: #0d6efd;
    font-weight: 600;
}

/* ── Modal ── */

.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.modal-dialog {
    background: #fff;
    border-radius: 10px;
    padding: 1.75rem;
    max-width: 400px;
    width: 90%;
    box-shadow: 0 10px 40px rgba(0,0,0,0.15);
}

.modal-dialog h4 {
    margin: 0 0 0.75rem;
    font-size: 1.1rem;
}

.modal-dialog p {
    margin: 0 0 1.25rem;
    font-size: 0.92rem;
    color: #495057;
}

/* ── Radio group ── */

.radio-group {
    display: flex;
    gap: 1.25rem;
    margin-top: 0.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.92rem;
    cursor: pointer;
    color: #212529;
}

.radio-item input[type="radio"] {
    accent-color: #0d6efd;
}

/* ── Preview area ── */

.preview-box {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    transition: all 0.2s;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
