}

.preview-font-sm {
    font-size: 0.82rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

.preview-compact {
    padding: 0.6rem 0.85rem;
    line-height: 1.3;
