    color: #fff;
}

.preview-dark .preview-btn {
    background: #6ea8fe;
    color: #1e1e2e;
}

/* ── Toast ── */

.toast-message {
    position: fixed;
    bottom: 2rem;
    right: 2rem;
    background: #198754;
    color: #fff;
    padding: 0.75rem 1.5rem;
    border-radius: 8px;
    font-size: 0.9rem;
    box-shadow: 0 4px 20px rgba(0,0,0,0.15);
