    animation: slideIn 0.25s ease-out;
}

.toast-error {
    background: #dc3545;
}

@keyframes slideIn {
    from { transform: translateY(20px); opacity: 0; }
    to   { transform: translateY(0);    opacity: 1; }
}

/* ── Loading ── */

.loading-spinner {
    text-align: center;
    padding: 3rem;
    color: #6c757d;
    font-size: 1rem;
}

