{"file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_719b9314b6014e88921a3b55014142e6.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li class="@(section == _activeSection ? "active" : "")" @onclick="() => SetSection(section)">
                    <span class="nav-icon">@GetSectionIcon(section)</span>
                    @section
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">Loading…</div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfile()
                    break;
                case "Notifications":
                    @RenderNotifications()
                    break;
                case "Security":
                    @RenderSecurity()
                    break;
                case "Appearance":
                    @RenderAppearance()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "")">@_toastText</div>
        }
    </div>
</div>

@* ──────────── Profile Section ──────────── *@

@code {
