@page "/settings"
@rendermode InteractiveServer
@using sv_719b9314b6014e88921a3b55014142e6.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li class="@(section == _activeSection ? "active" : "")" @onclick="() => SetSection(section)">
                    <span class="nav-icon">@GetSectionIcon(section)</span>
                    @section
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">Loading…</div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfile()
                    break;
                case "Notifications":
                    @RenderNotifications()
                    break;
                case "Security":
                    @RenderSecurity()
                    break;
                case "Appearance":
                    @RenderAppearance()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "")">@_toastText</div>
        }
    </div>
</div>

@* ──────────── Profile Section ──────────── *@

@code {
    private RenderFragment RenderProfile() => __builder =>
    {
        <section class="settings-section">
            <h2>Profile</h2>
            <div class="avatar-area">
                <img src="@_profileDisplayName" alt="avatar" class="avatar-preview"
                     onerror="this.style.display='none'" />
                @* Show the avatar from the URL field *@
                @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                {
                    <img src="@_profileAvatarUrl" alt="avatar" class="avatar-preview" />
                }
                else
                {
                    <div class="avatar-placeholder">No avatar</div>
                }
                <span class="avatar-url-label">@_profileAvatarUrl</span>
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" @bind="_profileDisplayName" class="form-input" />
            </div>
            <div class="form-group">
                <label>Email</label>
                <input type="email" @bind="_profileEmail" class="form-input" />
            </div>
            <div class="form-group">
                <label>Avatar URL</label>
                <input type="url" @bind="_profileAvatarUrl" class="form-input" />
            </div>
            <div class="form-group">
                <label>Bio</label>
                <textarea @bind="_profileBio" class="form-input form-textarea" rows="4"></textarea>
            </div>
            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
