@* ──────────── Security Section ──────────── *@

@code {
    private RenderFragment RenderSecurity() => __builder =>
    {
        <section class="settings-section">
            <h2>Security</h2>

            @* Change Password Panel *@
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>Change Password</span>
                    <span class="chevron @(_passwordPanelOpen ? "open" : "")">▸</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label>Current Password</label>
                            <input type="password" @bind="_currentPassword" class="form-input" />
                        </div>
                        <div class="form-group">
                            <label>New Password</label>
                            <input type="password" @bind="_newPassword" class="form-input" />
                        </div>
                        <div class="form-group">
                            <label>Confirm Password</label>
                            <input type="password" @bind="_confirmPassword" class="form-input" />
                        </div>
