@* ──────────── Code-behind ──────────── *@

@code {
    // Section navigation
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _toastVisible;
    private string _toastText = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile state
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // Notifications state
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeeklyDigest;
    private List<string> _mutedChannels = [];
    private readonly List<string> _allChannels = ["announcements", "marketing", "social", "engineering", "support"];

    // Security state
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private readonly string _currentSessionId = "sess-1"; // Treat first session as current
    private bool _revokeConfirmVisible;
    private string _revokeSessionId = "";
    private string _revokeDeviceName = "";

    // Appearance state
    private string _appTheme = "Light";
    private string _appFontSize = "Medium";
    private string _appLanguage = "English";
    private bool _appCompactMode;
    private readonly List<string> _languages = ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        var profile = profileTask.Result;
        _savedProfile = profile;
        ApplyProfile(profile);

        var notif = notifTask.Result;
        _notifEmail = notif.EmailNotifications;
        _notifPush = notif.PushNotifications;
        _notifWeeklyDigest = notif.WeeklyDigest;
        _mutedChannels = new List<string>(notif.MutedChannels);

        var security = securityTask.Result;
        _twoFactorEnabled = security.TwoFactorEnabled;
        _lastPasswordChange = security.LastPasswordChange;
        _sessions = new List<ActiveSession>(security.Sessions);

        var appearance = appearanceTask.Result;
        _appTheme = appearance.Theme;
        _appFontSize = appearance.FontSize;
        _appLanguage = appearance.Language;
        _appCompactMode = appearance.CompactMode;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;
    }

    private void SetSection(string section) => _activeSection = section;

    // ── Profile ──

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notifications ──

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!muted)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifWeeklyDigest, new List<string>(_mutedChannels));
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        ShowToast("Notification preferences saved.");
    }

    // ── Security ──

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Password cannot be empty.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("Passwords do not match.", isError: true);
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _lastPasswordChange = DateTime.UtcNow;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(string sessionId, string deviceName)
    {
        _revokeSessionId = sessionId;
        _revokeDeviceName = deviceName;
        _revokeConfirmVisible = true;
    }

    private async Task ConfirmRevoke()
    {
        await SettingsService.RevokeSessionAsync(_revokeSessionId);
        _sessions.RemoveAll(s => s.Id == _revokeSessionId);
        _revokeConfirmVisible = false;
        ShowToast("Session revoked.");
    }

    private void CancelRevoke() => _revokeConfirmVisible = false;

    // ── Appearance ──

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_appTheme, _appFontSize, _appLanguage, _appCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        ShowToast("Appearance settings saved.");
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string> { "preview-area" };
        classes.Add(_appTheme switch { "Dark" => "preview-dark", "System" => "preview-system", _ => "preview-light" });
        classes.Add(_appFontSize switch { "Small" => "preview-font-sm", "Large" => "preview-font-lg", _ => "preview-font-md" });
        if (_appCompactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    // ── Helpers ──

    private string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastText = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }
}

