toolArgs.file_text:
/* ── Layout ── */

.settings-layout {
    display: flex;
    min-height: calc(100vh - 5rem);
    gap: 0;
}

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 600;
    color: #495057;
}

.sidebar-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.sidebar-nav li {
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 0.6rem;
    color: #495057;
    font-size: 0.95rem;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-nav li:hover {
    background: #e9ecef;
}

.sidebar-nav li.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 780px;
    position: relative;
}

.settings-section h2 {
    margin: 0 0 1.5rem;
    font-size: 1.5rem;
    font-weight: 600;
    color: #212529;
}

/* ── Form elements ── */

.form-group {
    margin-bottom: 1.25rem;
}

.form-group label,
.group-label {
    display: block;
    margin-bottom: 0.35rem;
    font-weight: 500;
    font-size: 0.9rem;
    color: #495057;
}

.form-input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
    transition: border-color 0.15s;
    background: #fff;
    box-sizing: border-box;
}

.form-input:focus {
    outline: none;
    border-color: #86b7fe;
    box-shadow: 0 0 0 3px rgba(13,110,253,.15);
}

.form-textarea {
    resize: vertical;
    font-family: inherit;
}

select.form-input {
    appearance: auto;
}

/* ── Avatar ── */

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.5rem;
}

.avatar-preview {
    width: 72px;
    height: 72px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

.avatar-placeholder {
    width: 72px;
    height: 72px;
    border-radius: 50%;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.8rem;
    color: #6c757d;
}

.avatar-url-label {
    font-size: 0.82rem;
    color: #6c757d;
    word-break: break-all;
    max-width: 300px;
}

/* ── Buttons ── */

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn {
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s, opacity 0.15s;
}

.btn:hover {
    opacity: 0.88;
}

.btn-primary {
    background: #0d6efd;
    color: #fff;
}

.btn-secondary {
    background: #e9ecef;
    color: #495057;
}

.btn-danger {
    background: #dc3545;
    color: #fff;
}

.btn-sm {
    padding: 0.3rem 0.75rem;
    font-size: 0.82rem;
}

/* ── Toggle switch ── */

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-label {
    font-size: 0.95rem;
    color: #212529;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.switch {
    position: relative;
    width: 44px;
    height: 24px;
    display: inline-block;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    inset: 0;
    background: #ccc;
    border-radius: 24px;
    cursor: pointer;
    transition: background 0.2s;
}

.slider::before {
    content: "";
    position: absolute;
    width: 18px;
    height: 18px;
    left: 3px;
    bottom: 3px;
    background: #fff;
    border-radius: 50%;
    transition: transform 0.2s;
}

.switch input:checked + .slider {
    background: #0d6efd;
}

.switch input:checked + .slider::before {
    transform: translateX(20px);
}

/* ── Channels ── */

.sub-heading {
    font-size: 1rem;
    font-weight: 600;
    margin: 1.5rem 0 0.75rem;
    color: #495057;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.92rem;
    cursor: pointer;
    color: #212529;
}

.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #0d6efd;
}

/* ── Expandable panel ── */

.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

.panel-header {
    width: 100%;
    background: #f8f9fa;
    border: none;
    padding: 0.85rem 1rem;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: #212529;
}

.panel-header:hover {
    background: #e9ecef;
}

.chevron {
    transition: transform 0.2s;
    font-size: 1rem;
}

.chevron.open {
    transform: rotate(90deg);
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

.hint-text {
    font-size: 0.82rem;
    color: #6c757d;
    margin: 0.5rem 0 0;
}

/* ── Status badge ── */

.status-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.55rem;
    border-radius: 10px;
    font-weight: 600;
    text-transform: uppercase;
}

.status-on {
    background: #d1e7dd;
    color: #0f5132;
}

.status-off {
    background: #f8d7da;
    color: #842029;
}

/* ── Table ── */

.table-wrapper {
    overflow-x: auto;
}

.data-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.data-table th {
    text-align: left;
    padding: 0.6rem 0.75rem;
    border-bottom: 2px solid #dee2e6;
    color: #495057;
    font-weight: 600;
    font-size: 0.82rem;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.data-table td {
    padding: 0.65rem 0.75rem;
    border-bottom: 1px solid #f0f0f0;
    color: #212529;
}

.current-label {
    font-size: 0.8rem;
    color: #0d6efd;
    font-weight: 600;
}

/* ── Modal ── */

.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.modal-dialog {
    background: #fff;
    border-radius: 10px;
    padding: 1.75rem;
    max-width: 400px;
    width: 90%;
    box-shadow: 0 10px 40px rgba(0,0,0,0.15);
}

.modal-dialog h4 {
    margin: 0 0 0.75rem;
    font-size: 1.1rem;
}

.modal-dialog p {
    margin: 0 0 1.25rem;
    font-size: 0.92rem;
    color: #495057;
}

/* ── Radio group ── */

.radio-group {
    display: flex;
    gap: 1.25rem;
    margin-top: 0.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.92rem;
    cursor: pointer;
    color: #212529;
}

.radio-item input[type="radio"] {
    accent-color: #0d6efd;
}

/* ── Preview area ── */

.preview-box {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    transition: all 0.2s;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-font-sm {
    font-size: 0.82rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

.preview-compact {
    padding: 0.6rem 0.85rem;
    line-height: 1.3;
}

.preview-btn {
    padding: 0.4rem 1rem;
    border: none;
    border-radius: 5px;
    cursor: default;
    font-size: inherit;
}

.preview-light .preview-btn,
.preview-system .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.preview-dark .preview-btn {
    background: #6ea8fe;
    color: #1e1e2e;
}

/* ── Toast ── */

.toast-message {
    position: fixed;
    bottom: 2rem;
    right: 2rem;
    background: #198754;
    color: #fff;
    padding: 0.75rem 1.5rem;
    border-radius: 8px;
    font-size: 0.9rem;
    box-shadow: 0 4px 20px rgba(0,0,0,0.15);
    z-index: 2000;
    animation: slideIn 0.25s ease-out;
}

.toast-error {
    background: #dc3545;
}

@keyframes slideIn {
    from { transform: translateY(20px); opacity: 0; }
    to   { transform: translateY(0);    opacity: 1; }
}

/* ── Loading ── */

.loading-spinner {
    text-align: center;
    padding: 3rem;
    color: #6c757d;
    font-size: 1rem;
}

